#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * Free Space Management using Bit Vector (Bitmap)
 * Supports: single block allocation, contiguous allocation, deallocation
 */

typedef struct {
 int total_blocks;
 unsigned char *bitmap; // Dynamic bitmap array
} BitVectorFS;

// Initialize bit vector for given number of blocks
BitVectorFS* init_bitvector(int total_blocks) {
 BitVectorFS *fs = (BitVectorFS*)malloc(sizeof(BitVectorFS));
 fs->total_blocks = total_blocks;

 // Calculate bytes needed: (blocks + 7) / 8
 int bytes_needed = (total_blocks + 7) / 8;
 fs->bitmap = (unsigned char*)calloc(bytes_needed, 1); // Zero-initialized

 return fs;
}

// Check if a specific block is allocated
int is_allocated(BitVectorFS *fs, int block_num) {
 if (block_num < 0 || block_num >= fs->total_blocks) return -1;

 int byte_index = block_num / 8;
 int bit_index = block_num % 8;

 return (fs->bitmap[byte_index] >> bit_index) & 1;
}

// Set block as allocated (set bit to 1)
void set_allocated(BitVectorFS *fs, int block_num) {
 if (block_num < 0 || block_num >= fs->total_blocks) return;

 int byte_index = block_num / 8;
 int bit_index = block_num % 8;

 fs->bitmap[byte_index] |= (1 << bit_index);
}

// Set block as free (clear bit to 0)
void set_free(BitVectorFS *fs, int block_num) {
 if (block_num < 0 || block_num >= fs->total_blocks) return;

 int byte_index = block_num / 8;
 int bit_index = block_num % 8;

 fs->bitmap[byte_index] &= ~(1 << bit_index);
}

// Allocate a single block (optionally at preferred location)
int allocate_block(BitVectorFS *fs, int preferred) {
 // Try preferred block first
 if (preferred >= 0 && preferred < fs->total_blocks) {
 if (!is_allocated(fs, preferred)) {
 set_allocated(fs, preferred);
 return preferred;
 }
 }

 // Search for first free block
 for (int i = 0; i < fs->total_blocks; i++) {
 if (!is_allocated(fs, i)) {
 set_allocated(fs, i);
 return i;
 }
 }

 return -1; // No free blocks
}

// Allocate N contiguous blocks
int allocate_contiguous(BitVectorFS *fs, int num_blocks) {
 if (num_blocks <= 0) return -1;

 for (int start = 0; start <= fs->total_blocks - num_blocks; start++) {
 int all_free = 1;

 // Check if all blocks from start are free
 for (int offset = 0; offset < num_blocks; offset++) {
 if (is_allocated(fs, start + offset)) {
 all_free = 0;
 break;
 }
 }

 if (all_free) {
 // Mark all blocks as allocated
 for (int offset = 0; offset < num_blocks; offset++) {
 set_allocated(fs, start + offset);
 }
 return start;
 }
 }

 return -1; // No contiguous space
}

// Free a block
int free_block(BitVectorFS *fs, int block_num) {
 if (block_num < 0 || block_num >= fs->total_blocks) return 0;

 set_free(fs, block_num);
 return 1;
}

// Print bitmap in binary format
void print_bitmap(BitVectorFS *fs) {
 printf("Bitmap: ");
 for (int i = 0; i < fs->total_blocks; i++) {
 printf("%d", is_allocated(fs, i));
 }
 printf("\n");
}

// Count free blocks
int count_free(BitVectorFS *fs) {
 int count = 0;
 for (int i = 0; i < fs->total_blocks; i++) {
 if (!is_allocated(fs, i)) count++;
 }
 return count;
}

// Print statistics
void print_stats(BitVectorFS *fs) {
 int free_count = count_free(fs);
 int bitmap_bytes = (fs->total_blocks + 7) / 8;

 printf("\n=== Statistics ===\n");
 printf("Total blocks: %d\n", fs->total_blocks);
 printf("Free blocks: %d\n", free_count);
 printf("Allocated: %d\n", fs->total_blocks - free_count);
 printf("Bitmap size: %d bytes\n", bitmap_bytes);
 printf("Utilization: %.1f%%\n", 
 (fs->total_blocks - free_count) * 100.0 / fs->total_blocks);
}

int main() {
 printf("=== C Bit Vector Free Space Management ===\n\n");

 // Create FS with 20 blocks
 BitVectorFS *fs = init_bitvector(20);

 printf("Initial state: ");
 print_bitmap(fs);

 // Allocate some blocks
 printf("\n--- Allocating 3 blocks ---\n");
 int b1 = allocate_block(fs, 5); // Try preferred
 int b2 = allocate_block(fs, -1);
 int b3 = allocate_block(fs, -1);
 printf("Allocated: %d, %d, %d\n", b1, b2, b3);
 print_bitmap(fs);

 // Allocate contiguous blocks
 printf("\n--- Allocating 4 contiguous blocks ---\n");
 int start = allocate_contiguous(fs, 4);
 printf("Contiguous allocation started at: %d\n", start);
 print_bitmap(fs);

 // Free a block
 printf("\n--- Freeing block 6 ---\n");
 free_block(fs, 6);
 print_bitmap(fs);

 // Print statistics
 print_stats(fs);

 // Cleanup
 free(fs->bitmap);
 free(fs);

 return 0;
}
